// Reusable, audit-ready draft procedures for the 12 controlled documents.
// Generic ISO-style SOPs (Purpose, Scope, Definitions, Roles, Procedure, Records, References).
// Rich-text HTML; edited in-system. Customers adapt to their own organisation.
export const drafts: Record<number, string> = {
  1: "<h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:2px 0 7px;letter-spacing:-.1px\">1. Purpose</h3><p style=\"margin:0 0 9px\">This procedure defines how logical access to information systems, applications and data is requested, approved, provisioned, reviewed and revoked. It ensures access is granted on a least-privilege, need-to-know basis and that every grant is authorised and accountable.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">2. Scope</h3><p style=\"margin:0 0 9px\">Applies to all information systems, cloud services, applications, databases and network resources owned or operated by the organisation, and to all user types: employees, contractors, temporary staff, service/system accounts and authorised third parties. Physical access is addressed in a separate procedure.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">3. Definitions</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Least privilege</strong> — a user or process is granted only the access required to perform its function.</li><li style=\"margin:0 0 5px\"><strong>RBAC</strong> — role-based access control; permissions are assigned to roles, and roles to users.</li><li style=\"margin:0 0 5px\"><strong>Privileged access</strong> — administrative or elevated rights capable of changing system configuration, security settings or other users’ access.</li><li style=\"margin:0 0 5px\"><strong>JML</strong> — Joiner / Mover / Leaver, the events that trigger access changes.</li><li style=\"margin:0 0 5px\"><strong>MFA</strong> — multi-factor authentication.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">4. Roles &amp; responsibilities</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Information Security Officer (ISO)</strong> — owns this procedure, approves privileged/administrative access and leads periodic access reviews.</li><li style=\"margin:0 0 5px\"><strong>IT / Managed Service Provider</strong> — provisions and de-provisions access, enforces MFA and maintains access logs.</li><li style=\"margin:0 0 5px\"><strong>System owner</strong> — defines roles for their system and approves standard access requests.</li><li style=\"margin:0 0 5px\"><strong>Line manager</strong> — raises requests, confirms the business need and validates access at review.</li><li style=\"margin:0 0 5px\"><strong>User</strong> — uses granted access responsibly and reports any access no longer needed.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">5. Procedure</h3><ol style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 6px\"><strong>Request.</strong> Access is requested through the IT service desk, stating the system, the role/permission set, and a business justification. The user’s line manager confirms the need.</li><li style=\"margin:0 0 6px\"><strong>Approval.</strong> The system owner approves standard access; the ISO additionally approves any privileged or administrative access.</li><li style=\"margin:0 0 6px\"><strong>Provisioning.</strong> IT grants access using the pre-defined role within two business days. MFA is mandatory on all accounts; access without MFA is not permitted.</li><li style=\"margin:0 0 6px\"><strong>Least privilege.</strong> Default is deny. Elevated rights are time-bound and granted only for the specific task; standing administrative rights are avoided where technically feasible.</li><li style=\"margin:0 0 6px\"><strong>Joiner / Mover / Leaver.</strong> HR notifies IT of starters, role changes and leavers. Access is adjusted within one business day of a role change and fully revoked on the termination date.</li><li style=\"margin:0 0 6px\"><strong>Access reviews.</strong> Privileged access is reviewed quarterly and general user access semi-annually by the relevant owner. Findings are remediated and the review is signed off.</li><li style=\"margin:0 0 6px\"><strong>Service and shared accounts.</strong> Each is assigned a named owner, credentials are stored in the approved vault, and interactive logon is restricted.</li></ol><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">6. Records &amp; evidence</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Access request and approval tickets.</li><li style=\"margin:0 0 5px\">Quarterly/semi-annual access-review reports with sign-off.</li><li style=\"margin:0 0 5px\">MFA enrolment and authentication logs.</li><li style=\"margin:0 0 5px\">Leaver revocation confirmations.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">7. References</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Information Security Policy §7.</li><li style=\"margin:0 0 5px\">ISO/IEC 27001 A.5.15, A.5.16, A.5.18, A.8.2, A.8.5.</li><li style=\"margin:0 0 5px\">NIS2 Directive, Article 21 (access control & asset management).</li></ul>",
  2: "<h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:2px 0 7px;letter-spacing:-.1px\">1. Purpose</h3><p style=\"margin:0 0 9px\">This procedure establishes how information-security events and incidents are detected, reported, classified, contained, resolved and learned from, so that impact is minimised and legal, regulatory and contractual notification obligations are met.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">2. Scope</h3><p style=\"margin:0 0 9px\">Applies to all information-security events affecting the confidentiality, integrity or availability of the organisation’s information or that of its customers — including suspected breaches, malware, account compromise, data loss and service outages — regardless of whether systems are on-premises, cloud or supplier-operated.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">3. Definitions</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Event</strong> — an observed occurrence that may be security-relevant.</li><li style=\"margin:0 0 5px\"><strong>Incident</strong> — an event, or series of events, that compromises information security or business operations.</li><li style=\"margin:0 0 5px\"><strong>Severity</strong> — the classification (e.g. Low / Medium / High / Critical) driving response and escalation.</li><li style=\"margin:0 0 5px\"><strong>Personal data breach</strong> — a breach leading to accidental or unlawful destruction, loss, alteration or unauthorised disclosure of personal data.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">4. Roles &amp; responsibilities</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>All staff</strong> — report suspected incidents immediately via the defined channel.</li><li style=\"margin:0 0 5px\"><strong>Information Security Officer (ISO)</strong> — triages, classifies and coordinates response; maintains the incident log.</li><li style=\"margin:0 0 5px\"><strong>Executive Management</strong> — is informed of High/Critical incidents and authorises external notification.</li><li style=\"margin:0 0 5px\"><strong>IT / MSP</strong> — performs containment, eradication and recovery under ISO direction.</li><li style=\"margin:0 0 5px\"><strong>DPO / legal (where applicable)</strong> — assesses personal-data and regulatory notification obligations.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">5. Procedure</h3><ol style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 6px\"><strong>Report.</strong> Anyone who detects a suspected incident reports it without delay through the single reporting channel (service desk / security mailbox). No blame attaches to good-faith reporting.</li><li style=\"margin:0 0 6px\"><strong>Triage & classify.</strong> The ISO confirms the incident, assigns a severity and opens an incident record. High/Critical incidents are escalated to Executive Management the same working day.</li><li style=\"margin:0 0 6px\"><strong>Contain.</strong> Immediate actions are taken to limit spread and preserve evidence (isolate hosts, disable accounts, capture logs).</li><li style=\"margin:0 0 6px\"><strong>Notify.</strong> Where a personal-data breach is likely, the supervisory authority is notified within 72 hours; affected customers and authorities are notified per NIS2 timelines and contractual terms.</li><li style=\"margin:0 0 6px\"><strong>Eradicate & recover.</strong> Root cause is removed and systems restored from trusted sources; integrity is verified before return to service.</li><li style=\"margin:0 0 6px\"><strong>Post-incident review.</strong> Within ten working days a review captures timeline, root cause, impact and corrective/preventive actions.</li><li style=\"margin:0 0 6px\"><strong>Log & track.</strong> All incidents and actions are recorded in the incident log and tracked to closure.</li></ol><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">6. Records &amp; evidence</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Incident records and the central incident log.</li><li style=\"margin:0 0 5px\">Notification correspondence with authorities/customers.</li><li style=\"margin:0 0 5px\">Evidence packages (logs, images) retained per legal hold.</li><li style=\"margin:0 0 5px\">Post-incident review reports and CAPA tracking.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">7. References</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Information Security Policy §11.</li><li style=\"margin:0 0 5px\">ISO/IEC 27001 A.5.24–A.5.28.</li><li style=\"margin:0 0 5px\">NIS2 Directive, Article 23 (incident reporting); GDPR Articles 33–34.</li></ul>",
  3: "<h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:2px 0 7px;letter-spacing:-.1px\">1. Purpose</h3><p style=\"margin:0 0 9px\">This procedure defines how critical data and systems are backed up, protected and restored, so that the organisation can recover from data loss, corruption or ransomware within agreed recovery objectives.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">2. Scope</h3><p style=\"margin:0 0 9px\">Applies to all systems and data classified as important or critical in the asset inventory, including business applications, customer data, configuration and, where relevant, regulated (GxP) records. Endpoint user data synced to managed cloud storage is included.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">3. Definitions</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>RPO</strong> — Recovery Point Objective; maximum acceptable data loss measured in time.</li><li style=\"margin:0 0 5px\"><strong>RTO</strong> — Recovery Time Objective; maximum acceptable time to restore a service.</li><li style=\"margin:0 0 5px\"><strong>3-2-1 rule</strong> — three copies, on two media types, one off-site/immutable.</li><li style=\"margin:0 0 5px\"><strong>Immutable backup</strong> — a copy that cannot be altered or deleted for a defined retention period.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">4. Roles &amp; responsibilities</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Information Security Officer (ISO)</strong> — owns the procedure and approves backup scope and retention.</li><li style=\"margin:0 0 5px\"><strong>IT / MSP</strong> — configures, monitors and maintains backups and performs restores.</li><li style=\"margin:0 0 5px\"><strong>System owner</strong> — defines RPO/RTO and validates restored data.</li><li style=\"margin:0 0 5px\"><strong>QA (regulated systems)</strong> — confirms integrity of restored GxP records where applicable.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">5. Procedure</h3><ol style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 6px\"><strong>Define requirements.</strong> For each in-scope system the owner sets the RPO, RTO and retention period, recorded in the backup register.</li><li style=\"margin:0 0 6px\"><strong>Configure backups.</strong> IT implements automated backups following the 3-2-1 principle, with at least one immutable or off-site copy protected from ransomware.</li><li style=\"margin:0 0 6px\"><strong>Encrypt & protect.</strong> Backups are encrypted at rest and in transit; access to backup systems is restricted and logged.</li><li style=\"margin:0 0 6px\"><strong>Monitor.</strong> Backup success/failure is monitored daily; failures are investigated and resolved, and repeated failures escalated to the ISO.</li><li style=\"margin:0 0 6px\"><strong>Restore testing.</strong> A documented restore test of critical systems is performed at least annually (and after major change), verifying both recoverability and data integrity against RPO/RTO.</li><li style=\"margin:0 0 6px\"><strong>Recovery.</strong> On a real event, restores follow this procedure; the system owner (and QA for regulated data) confirms completeness and integrity before return to service.</li></ol><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">6. Records &amp; evidence</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Backup register (scope, RPO/RTO, retention).</li><li style=\"margin:0 0 5px\">Backup monitoring logs and failure follow-ups.</li><li style=\"margin:0 0 5px\">Annual restore-test reports with results and sign-off.</li><li style=\"margin:0 0 5px\">Recovery records for actual events.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">7. References</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Information Security Policy §10.</li><li style=\"margin:0 0 5px\">ISO/IEC 27001 A.8.13, A.8.14.</li><li style=\"margin:0 0 5px\">NIS2 Directive, Article 21 (business continuity & backup); EU GMP Annex 11 §7.2 (data & backup).</li></ul>",
  4: "<h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:2px 0 7px;letter-spacing:-.1px\">1. Purpose</h3><p style=\"margin:0 0 9px\">This procedure defines how suppliers and service providers that process, store or access the organisation’s information — or that of its customers — are assessed, contracted and monitored for information-security and continuity risk.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">2. Scope</h3><p style=\"margin:0 0 9px\">Applies to all third parties with logical or physical access to organisational or customer information, or that deliver ICT services material to operations, including cloud providers, software vendors, sub-processors and managed service providers.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">3. Definitions</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Critical supplier</strong> — a supplier whose failure or compromise would materially affect security, compliance or continuity.</li><li style=\"margin:0 0 5px\"><strong>Sub-processor</strong> — a third party engaged by a supplier to process data on the organisation’s behalf.</li><li style=\"margin:0 0 5px\"><strong>DPA</strong> — Data Processing Agreement.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">4. Roles &amp; responsibilities</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Information Security Officer (ISO)</strong> — owns the procedure, sets assessment criteria and approves critical suppliers.</li><li style=\"margin:0 0 5px\"><strong>Contract/business owner</strong> — initiates the relationship and maintains day-to-day oversight.</li><li style=\"margin:0 0 5px\"><strong>Procurement / legal</strong> — ensures security, DPA and continuity clauses are in contracts.</li><li style=\"margin:0 0 5px\"><strong>Executive Management</strong> — accepts residual risk for critical suppliers.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">5. Procedure</h3><ol style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 6px\"><strong>Classify.</strong> Before engagement the business owner records the data and access involved and classifies the supplier’s criticality.</li><li style=\"margin:0 0 6px\"><strong>Due diligence.</strong> Security is assessed proportionally — e.g. security questionnaire, ISO 27001 / SOC 2 evidence, penetration-test summaries — before contract signature.</li><li style=\"margin:0 0 6px\"><strong>Contract.</strong> Contracts include security requirements, breach-notification timelines, audit rights, sub-processor control and, where personal data is involved, a DPA.</li><li style=\"margin:0 0 6px\"><strong>Approve.</strong> The ISO approves critical suppliers; residual risk is accepted by Executive Management and recorded.</li><li style=\"margin:0 0 6px\"><strong>Onboard.</strong> Access is provisioned per the Access Management procedure on least-privilege terms.</li><li style=\"margin:0 0 6px\"><strong>Monitor & re-assess.</strong> Critical suppliers are re-assessed at least annually and on significant change; performance and incidents are tracked.</li><li style=\"margin:0 0 6px\"><strong>Offboard.</strong> On exit, access is revoked, data returned or securely deleted, and deletion confirmed in writing.</li></ol><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">6. Records &amp; evidence</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Supplier register with criticality and assessment status.</li><li style=\"margin:0 0 5px\">Completed due-diligence questionnaires and certificates.</li><li style=\"margin:0 0 5px\">Signed contracts, DPAs and sub-processor lists.</li><li style=\"margin:0 0 5px\">Re-assessment records and offboarding/deletion confirmations.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">7. References</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Information Security Policy §12.</li><li style=\"margin:0 0 5px\">ISO/IEC 27001 A.5.19–A.5.23.</li><li style=\"margin:0 0 5px\">NIS2 Directive, Article 21 (supply-chain security).</li></ul>",
  5: "<h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:2px 0 7px;letter-spacing:-.1px\">1. Purpose</h3><p style=\"margin:0 0 9px\">This procedure defines how customer data is received, classified, stored, transmitted, accessed and disposed of, ensuring confidentiality, integrity and availability throughout its lifecycle and honouring contractual and regulatory commitments.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">2. Scope</h3><p style=\"margin:0 0 9px\">Applies to all customer data in any form or location — production, test, backup and endpoint — handled by staff, systems or approved suppliers. Where customer data includes personal or regulated (GxP) records, the additional controls in the relevant procedures also apply.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">3. Definitions</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Customer data</strong> — any information owned by or relating to a customer that is entrusted to the organisation.</li><li style=\"margin:0 0 5px\"><strong>Data segregation</strong> — logical or physical separation of one customer’s data from another’s.</li><li style=\"margin:0 0 5px\"><strong>Data minimisation</strong> — collecting and retaining only what is necessary for the agreed purpose.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">4. Roles &amp; responsibilities</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Information Security Officer (ISO)</strong> — owns the procedure and monitors compliance.</li><li style=\"margin:0 0 5px\"><strong>Data owners</strong> — classify customer data and define access.</li><li style=\"margin:0 0 5px\"><strong>All staff</strong> — handle customer data strictly per classification and contract.</li><li style=\"margin:0 0 5px\"><strong>IT / MSP</strong> — implements storage, encryption and segregation controls.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">5. Procedure</h3><ol style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 6px\"><strong>Receive & classify.</strong> Customer data is received only through approved channels and classified on arrival per the Information Classification guideline.</li><li style=\"margin:0 0 6px\"><strong>Segregate.</strong> Each customer’s data is logically segregated; access is restricted to staff with a contractual need.</li><li style=\"margin:0 0 6px\"><strong>Store & encrypt.</strong> Data is stored only in approved, EU-hosted systems and encrypted at rest and in transit.</li><li style=\"margin:0 0 6px\"><strong>Access on need-to-know.</strong> Access follows least privilege; production customer data is not copied to unmanaged devices or non-approved tools.</li><li style=\"margin:0 0 6px\"><strong>Use of test data.</strong> Real customer data is not used in test environments unless masked/anonymised and contractually permitted.</li><li style=\"margin:0 0 6px\"><strong>Transmit securely.</strong> External transfers use encrypted, approved mechanisms; ad-hoc email of sensitive data is prohibited.</li><li style=\"margin:0 0 6px\"><strong>Retain & dispose.</strong> Data is retained only for the agreed period, then returned or securely destroyed, with destruction recorded.</li></ol><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">6. Records &amp; evidence</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Data classification and inventory of customer datasets.</li><li style=\"margin:0 0 5px\">Access grants and reviews for customer data.</li><li style=\"margin:0 0 5px\">Encryption and segregation configuration records.</li><li style=\"margin:0 0 5px\">Return/destruction certificates at end of retention.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">7. References</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Information Security Policy §13, §19.</li><li style=\"margin:0 0 5px\">ISO/IEC 27001 A.5.12, A.5.14, A.8.10–A.8.12.</li><li style=\"margin:0 0 5px\">GDPR Articles 5, 28, 32; EU GMP Annex 11 (where regulated).</li></ul>",
  6: "<h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:2px 0 7px;letter-spacing:-.1px\">1. Purpose</h3><p style=\"margin:0 0 9px\">This procedure sets out the acceptable and secure use of artificial-intelligence tools (including generative AI and AI-enabled features of other software) so the organisation gains their benefit without exposing confidential data, breaching privacy or introducing unmanaged risk.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">2. Scope</h3><p style=\"margin:0 0 9px\">Applies to all staff and contractors using AI tools for organisational work, whether standalone services, browser extensions or AI features embedded in approved applications, on any device used for work.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">3. Definitions</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Generative AI</strong> — tools that produce text, code, images or other content from prompts.</li><li style=\"margin:0 0 5px\"><strong>Prompt</strong> — the input provided to an AI tool, which may itself contain sensitive data.</li><li style=\"margin:0 0 5px\"><strong>Training/retention</strong> — whether a provider uses submitted inputs to train models or retains them.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">4. Roles &amp; responsibilities</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Information Security Officer (ISO)</strong> — owns the procedure, maintains the approved-tool list and assesses new tools.</li><li style=\"margin:0 0 5px\"><strong>Data owners</strong> — determine what data may be shared with AI tools.</li><li style=\"margin:0 0 5px\"><strong>All staff</strong> — use only approved tools and follow the input rules below.</li><li style=\"margin:0 0 5px\"><strong>Line managers</strong> — ensure their teams are aware of and follow this procedure.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">5. Procedure</h3><ol style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 6px\"><strong>Use approved tools only.</strong> AI tools must appear on the approved-tool list; the ISO assesses data handling, retention/training settings and hosting before approval.</li><li style=\"margin:0 0 6px\"><strong>Protect confidential data.</strong> Confidential, personal or customer data must not be entered into public AI tools. Only approved enterprise instances with contractual data protection may process such data, and only where permitted.</li><li style=\"margin:0 0 6px\"><strong>Human oversight.</strong> AI output is treated as a draft; a competent person reviews it for accuracy, bias and appropriateness before use or publication.</li><li style=\"margin:0 0 6px\"><strong>Attribution & IP.</strong> Staff verify licensing/IP implications and do not present AI output as a substitute for required professional judgement.</li><li style=\"margin:0 0 6px\"><strong>No unmanaged automation.</strong> AI tools are not connected to production systems or granted access to data stores without ISO review.</li><li style=\"margin:0 0 6px\"><strong>Report issues.</strong> Suspected data exposure through an AI tool is reported as a security incident.</li></ol><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">6. Records &amp; evidence</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Approved AI-tool list with assessment notes.</li><li style=\"margin:0 0 5px\">Data-handling assessments for each approved tool.</li><li style=\"margin:0 0 5px\">Records of exceptions and their approval.</li><li style=\"margin:0 0 5px\">Awareness acknowledgements from staff.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">7. References</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Information Security Policy §20.</li><li style=\"margin:0 0 5px\">ISO/IEC 27001 A.5.10, A.8.1; ISO/IEC 42001 (AI management, informative).</li><li style=\"margin:0 0 5px\">GDPR Articles 5, 6, 22 (where personal data / automated decisions are involved).</li></ul>",
  7: "<h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:2px 0 7px;letter-spacing:-.1px\">1. Purpose</h3><p style=\"margin:0 0 9px\">This procedure defines how staff connect remotely to customer environments so that access is authorised, secure, traceable and compliant with the customer’s and the organisation’s security requirements.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">2. Scope</h3><p style=\"margin:0 0 9px\">Applies to all remote access by staff or approved subcontractors to systems, networks or applications operated by or on behalf of customers, using any device or connection method.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">3. Definitions</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Jump host / bastion</strong> — a hardened intermediary system through which access is brokered and logged.</li><li style=\"margin:0 0 5px\"><strong>PAM</strong> — privileged access management; brokering, vaulting and session recording of privileged access.</li><li style=\"margin:0 0 5px\"><strong>Managed device</strong> — a device configured, patched and monitored under organisational control.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">4. Roles &amp; responsibilities</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Information Security Officer (ISO)</strong> — owns the procedure and approves standing customer access.</li><li style=\"margin:0 0 5px\"><strong>IT / MSP</strong> — maintains secure access infrastructure (VPN, jump hosts, PAM).</li><li style=\"margin:0 0 5px\"><strong>Engineer/consultant</strong> — connects only as authorised and follows customer rules.</li><li style=\"margin:0 0 5px\"><strong>Customer contact</strong> — authorises and periodically confirms the access granted.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">5. Procedure</h3><ol style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 6px\"><strong>Authorise.</strong> Access to a customer environment requires a documented authorisation from the customer and internal approval by the ISO, scoped to specific systems and duration.</li><li style=\"margin:0 0 6px\"><strong>Use managed, MFA-protected devices.</strong> Connections are made only from managed devices with current patches and endpoint protection, using MFA.</li><li style=\"margin:0 0 6px\"><strong>Broker & least privilege.</strong> Access is brokered through approved mechanisms (VPN, jump host/PAM); privileges are the minimum required and time-bound where possible.</li><li style=\"margin:0 0 6px\"><strong>Segregate.</strong> Credentials and sessions are kept separate per customer; shared credentials are avoided and, where unavoidable, vaulted and rotated.</li><li style=\"margin:0 0 6px\"><strong>Log & monitor.</strong> Sessions are logged (and recorded for privileged access where required); logs are retained per contract.</li><li style=\"margin:0 0 6px\"><strong>Follow customer rules.</strong> Where the customer’s security requirements are stricter, they take precedence.</li><li style=\"margin:0 0 6px\"><strong>Revoke.</strong> Access is removed promptly at end of engagement or on role change and confirmed with the customer.</li></ol><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">6. Records &amp; evidence</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Customer authorisations and internal approvals.</li><li style=\"margin:0 0 5px\">Access register per customer environment.</li><li style=\"margin:0 0 5px\">Session/PAM logs retained per contract.</li><li style=\"margin:0 0 5px\">Revocation confirmations.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">7. References</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Information Security Policy §14.</li><li style=\"margin:0 0 5px\">ISO/IEC 27001 A.6.7, A.8.5, A.8.15, A.8.16.</li><li style=\"margin:0 0 5px\">NIS2 Directive, Article 21 (secure remote access).</li></ul>",
  8: "<h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:2px 0 7px;letter-spacing:-.1px\">1. Purpose</h3><p style=\"margin:0 0 9px\">This procedure defines the additional controls applied when the organisation handles data or delivers services within regulated (GxP) contexts, ensuring computerised-system compliance, data integrity and electronic-record/signature requirements are met alongside the ISMS.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">2. Scope</h3><p style=\"margin:0 0 9px\">Applies to all projects, systems and records that fall within EU GMP Annex 11 / 21 CFR Part 11 scope, including regulated customer projects and any GxP-relevant computerised systems the organisation operates or supports.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">3. Definitions</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>GxP</strong> — good practice regulations (GMP/GDP/GLP/GCP) governing regulated activities.</li><li style=\"margin:0 0 5px\"><strong>CSV/CSA</strong> — computerised-system validation / assurance.</li><li style=\"margin:0 0 5px\"><strong>ALCOA+</strong> — data-integrity attributes: Attributable, Legible, Contemporaneous, Original, Accurate (+ Complete, Consistent, Enduring, Available).</li><li style=\"margin:0 0 5px\"><strong>Audit trail</strong> — a secure, computer-generated, time-stamped record of changes to regulated data.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">4. Roles &amp; responsibilities</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Executive Management</strong> — approves the GxP scope and accepts regulated risk.</li><li style=\"margin:0 0 5px\"><strong>Information Security Officer (ISO)</strong> — aligns ISMS controls with GxP requirements.</li><li style=\"margin:0 0 5px\"><strong>System owners</strong> — ensure their computerised systems are validated and maintained in a validated state.</li><li style=\"margin:0 0 5px\"><strong>QA</strong> — approves validation deliverables and periodic reviews.</li><li style=\"margin:0 0 5px\"><strong>Project leads</strong> — apply this procedure to regulated projects.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">5. Procedure</h3><ol style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 6px\"><strong>Determine GxP scope.</strong> Each system/project is assessed for GxP applicability and recorded in the regulated-systems list with its GxP risk.</li><li style=\"margin:0 0 6px\"><strong>Validate.</strong> Computerised systems are validated using a risk-based lifecycle (URS → risk assessment → IQ/OQ/PQ or equivalent CSA), with QA-approved deliverables.</li><li style=\"margin:0 0 6px\"><strong>Ensure data integrity.</strong> ALCOA+ is enforced: secure time-stamped audit trails, controlled changes, no shared logins for regulated actions, and periodic audit-trail review.</li><li style=\"margin:0 0 6px\"><strong>Electronic signatures.</strong> Where electronic signatures are used they meet Annex 11 / Part 11 — unique to the signer, re-authenticated, and permanently linked to the record and its meaning.</li><li style=\"margin:0 0 6px\"><strong>Change control.</strong> Changes to validated systems follow the Change Management procedure with GxP impact assessment and QA approval.</li><li style=\"margin:0 0 6px\"><strong>Periodic review.</strong> Validated systems undergo periodic review to confirm they remain fit for use and in a validated state.</li><li style=\"margin:0 0 6px\"><strong>Supplier oversight.</strong> GxP-relevant suppliers are assessed for their quality and validation capabilities.</li></ol><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">6. Records &amp; evidence</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Regulated-systems list and GxP risk assessments.</li><li style=\"margin:0 0 5px\">Validation packages (URS, risk, IQ/OQ/PQ) with QA approval.</li><li style=\"margin:0 0 5px\">Audit-trail review records and periodic-review reports.</li><li style=\"margin:0 0 5px\">Electronic-signature and change-control records.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">7. References</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Information Security Policy §15.</li><li style=\"margin:0 0 5px\">EU GMP Annex 11; US FDA 21 CFR Part 11; GAMP 5 (2nd ed.); ALCOA+ (MHRA/PIC-S data-integrity guidance).</li><li style=\"margin:0 0 5px\">ISO/IEC 27001 A.5.x, A.8.x (supporting controls).</li></ul>",
  9: "<h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:2px 0 7px;letter-spacing:-.1px\">1. Purpose</h3><p style=\"margin:0 0 9px\">This procedure defines how changes to information systems, infrastructure and security-relevant configuration are proposed, assessed, approved, implemented and reviewed, so that changes do not compromise security, availability or compliance.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">2. Scope</h3><p style=\"margin:0 0 9px\">Applies to all changes to production systems, network and security configuration, applications and — where relevant — validated (GxP) systems. Emergency changes are included with an expedited path. Routine, pre-approved standard changes may follow a lightweight route.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">3. Definitions</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Standard change</strong> — a low-risk, pre-authorised, repeatable change.</li><li style=\"margin:0 0 5px\"><strong>Normal change</strong> — a change requiring assessment and approval before implementation.</li><li style=\"margin:0 0 5px\"><strong>Emergency change</strong> — a change needed urgently to restore service or fix a security issue.</li><li style=\"margin:0 0 5px\"><strong>Rollback</strong> — the plan to revert a change if it fails.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">4. Roles &amp; responsibilities</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Information Security Officer (ISO)</strong> — owns the procedure and approves security-relevant changes.</li><li style=\"margin:0 0 5px\"><strong>System owner</strong> — assesses impact and authorises changes to their system.</li><li style=\"margin:0 0 5px\"><strong>IT / MSP</strong> — implements and tests changes and executes rollback if needed.</li><li style=\"margin:0 0 5px\"><strong>QA (regulated systems)</strong> — approves changes affecting validated systems.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">5. Procedure</h3><ol style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 6px\"><strong>Raise.</strong> A change request describes the change, reason, affected systems, risk/security and data-integrity impact, test approach and rollback plan.</li><li style=\"margin:0 0 6px\"><strong>Assess.</strong> The change is categorised (standard/normal/emergency) and its security, availability and (for GxP) validation impact assessed.</li><li style=\"margin:0 0 6px\"><strong>Approve.</strong> Normal changes are approved by the system owner and, where security-relevant, the ISO; GxP-affecting changes also require QA approval.</li><li style=\"margin:0 0 6px\"><strong>Test.</strong> Changes are tested in a non-production environment where feasible before deployment.</li><li style=\"margin:0 0 6px\"><strong>Implement.</strong> Changes are deployed in a controlled window with the rollback plan ready; segregation of duties is maintained between development and deployment where practical.</li><li style=\"margin:0 0 6px\"><strong>Emergency path.</strong> Emergency changes may be implemented first and documented and approved immediately after, within one working day.</li><li style=\"margin:0 0 6px\"><strong>Review & close.</strong> Post-implementation the outcome is verified and the change record closed; failed changes trigger a review.</li></ol><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">6. Records &amp; evidence</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Change requests with impact assessment and approvals.</li><li style=\"margin:0 0 5px\">Test evidence and deployment records.</li><li style=\"margin:0 0 5px\">Emergency-change justifications and after-the-fact approvals.</li><li style=\"margin:0 0 5px\">Post-implementation reviews and the change log.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">7. References</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Information Security Policy §16.</li><li style=\"margin:0 0 5px\">ISO/IEC 27001 A.8.32, A.8.9, A.8.31.</li><li style=\"margin:0 0 5px\">EU GMP Annex 11 §10 (change & configuration management, where regulated); NIS2 Article 21.</li></ul>",
  10: "<h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:2px 0 7px;letter-spacing:-.1px\">1. Purpose</h3><p style=\"margin:0 0 9px\">This procedure ensures that when a person leaves the organisation, or their engagement ends, all access is revoked and all assets and information are returned or securely handled, removing residual risk in a timely, verifiable way.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">2. Scope</h3><p style=\"margin:0 0 9px\">Applies to all leavers — employees, contractors and temporary staff — and to role changes that reduce entitlement. It covers logical access, physical access, hardware, credentials, tokens and organisational information held by the individual.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">3. Definitions</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Offboarding</strong> — the coordinated process of ending a person’s access and recovering assets.</li><li style=\"margin:0 0 5px\"><strong>Asset</strong> — any organisation-owned device, token, key or media issued to the individual.</li><li style=\"margin:0 0 5px\"><strong>Last working day</strong> — the effective date on which access must be revoked.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">4. Roles &amp; responsibilities</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>HR</strong> — initiates offboarding and communicates leaver details and dates.</li><li style=\"margin:0 0 5px\"><strong>Line manager</strong> — confirms assets held and knowledge transfer needs.</li><li style=\"margin:0 0 5px\"><strong>IT / MSP</strong> — revokes access, recovers/wipes devices and reclaims licences.</li><li style=\"margin:0 0 5px\"><strong>Information Security Officer (ISO)</strong> — verifies completion and handles exceptions.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">5. Procedure</h3><ol style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 6px\"><strong>Notify.</strong> HR notifies IT, the line manager and the ISO of the leaver and their last working day as early as possible.</li><li style=\"margin:0 0 6px\"><strong>Revoke access.</strong> All logical access (accounts, VPN, cloud services, customer environments) and physical access (badges, keys) are disabled on the last working day — immediately for involuntary or high-risk departures.</li><li style=\"margin:0 0 6px\"><strong>Recover assets.</strong> All issued hardware, tokens, keys and media are returned and logged; devices are wiped or securely re-provisioned.</li><li style=\"margin:0 0 6px\"><strong>Handle information.</strong> Business data is transferred to the manager; personal mailboxes/accounts are retained or deleted per the retention schedule.</li><li style=\"margin:0 0 6px\"><strong>Reclaim & rotate.</strong> Licences are reclaimed and any shared credentials the person knew are rotated.</li><li style=\"margin:0 0 6px\"><strong>Verify.</strong> The ISO confirms that access is revoked and assets returned; discrepancies are followed up and recorded.</li></ol><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">6. Records &amp; evidence</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Offboarding checklist per leaver, signed off.</li><li style=\"margin:0 0 5px\">Asset-return log and device-wipe confirmations.</li><li style=\"margin:0 0 5px\">Access-revocation confirmations across systems.</li><li style=\"margin:0 0 5px\">Records of any exceptions and their resolution.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">7. References</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Information Security Policy §7.5.</li><li style=\"margin:0 0 5px\">ISO/IEC 27001 A.6.1, A.6.5, A.5.11, A.8.1.</li><li style=\"margin:0 0 5px\">NIS2 Directive, Article 21 (human-resources security).</li></ul>",
  11: "<h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:2px 0 7px;letter-spacing:-.1px\">1. Purpose</h3><p style=\"margin:0 0 9px\">This guideline helps staff classify information by sensitivity and apply the right handling so that information receives protection proportionate to its value and to legal, contractual and regulatory obligations.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">2. Scope</h3><p style=\"margin:0 0 9px\">Applies to all information created, received or processed by the organisation, in any format (electronic, paper, verbal) and location, including customer information entrusted to the organisation.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">3. Definitions</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Public</strong> — information approved for release with no adverse impact.</li><li style=\"margin:0 0 5px\"><strong>Internal</strong> — for internal use; limited impact if disclosed.</li><li style=\"margin:0 0 5px\"><strong>Confidential</strong> — sensitive business, personal or customer information; disclosure would cause significant harm.</li><li style=\"margin:0 0 5px\"><strong>Restricted</strong> — the most sensitive information (e.g. special-category personal data, regulated records, secrets); disclosure would cause severe harm.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">4. Roles &amp; responsibilities</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Data owners</strong> — assign and review the classification of information they own.</li><li style=\"margin:0 0 5px\"><strong>Information Security Officer (ISO)</strong> — maintains this guideline and advises on classification.</li><li style=\"margin:0 0 5px\"><strong>All staff</strong> — classify information they create and handle it per its label.</li><li style=\"margin:0 0 5px\"><strong>IT / MSP</strong> — provides tools and controls that support each level.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">5. Procedure</h3><ol style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 6px\"><strong>Classify at creation.</strong> The author assigns the lowest classification consistent with the information’s sensitivity; when in doubt, treat as Confidential and consult the data owner.</li><li style=\"margin:0 0 6px\"><strong>Label.</strong> Where practical, documents and emails carry their classification (e.g. in the footer or subject) so recipients handle them correctly.</li><li style=\"margin:0 0 6px\"><strong>Handle by level.</strong> Apply the handling rules: <strong>Public</strong> — no restriction; <strong>Internal</strong> — share within the organisation only; <strong>Confidential</strong> — need-to-know, encrypt in transit, approved storage; <strong>Restricted</strong> — strict need-to-know, encryption at rest and in transit, access logging, no removable media without approval.</li><li style=\"margin:0 0 6px\"><strong>Storage & transmission.</strong> Confidential and Restricted information is stored only in approved systems and transmitted only by approved encrypted means.</li><li style=\"margin:0 0 6px\"><strong>Reclassify.</strong> Classification is reviewed when sensitivity changes; over-classification is corrected to avoid unnecessary friction.</li><li style=\"margin:0 0 6px\"><strong>Dispose securely.</strong> Information is retained per the retention schedule and disposed of securely (secure deletion / shredding) at end of life.</li></ol><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">6. Records &amp; evidence</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Classification scheme and handling matrix (this guideline).</li><li style=\"margin:0 0 5px\">Data owner assignments and classification decisions for key datasets.</li><li style=\"margin:0 0 5px\">Evidence of labelling in document templates.</li><li style=\"margin:0 0 5px\">Secure-disposal records for Restricted information.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">7. References</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Information Security Policy §5.</li><li style=\"margin:0 0 5px\">ISO/IEC 27001 A.5.12, A.5.13, A.8.10, A.8.12.</li><li style=\"margin:0 0 5px\">GDPR Article 5 (data minimisation & integrity); NIS2 Article 21.</li></ul>",
  12: "<h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:2px 0 7px;letter-spacing:-.1px\">1. Purpose</h3><p style=\"margin:0 0 9px\">This awareness material equips every employee to recognise and respond to common information-security risks, and sets out the security-awareness programme so that secure behaviour becomes part of everyday work.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">2. Scope</h3><p style=\"margin:0 0 9px\">Applies to all employees and contractors from onboarding onward, delivered as onboarding training, periodic refreshers and ongoing campaigns. It complements — and does not replace — the detailed procedures.</p><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">3. Definitions</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Phishing</strong> — fraudulent messages that try to trick you into revealing information or clicking malicious links.</li><li style=\"margin:0 0 5px\"><strong>Social engineering</strong> — manipulating people into breaking security (e.g. pretexting, urgency).</li><li style=\"margin:0 0 5px\"><strong>Strong authentication</strong> — a good passphrase plus multi-factor authentication.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">4. Roles &amp; responsibilities</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\"><strong>Information Security Officer (ISO)</strong> — owns the programme and maintains the material.</li><li style=\"margin:0 0 5px\"><strong>HR</strong> — ensures onboarding and refresher completion.</li><li style=\"margin:0 0 5px\"><strong>Line managers</strong> — reinforce secure behaviour in their teams.</li><li style=\"margin:0 0 5px\"><strong>All employees</strong> — complete training and apply what they learn.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">5. Procedure</h3><ol style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 6px\"><strong>What every employee must do.</strong> Use a strong, unique passphrase and MFA; lock your screen when away; verify unexpected requests (especially about money, credentials or data) through a known channel.</li><li style=\"margin:0 0 6px\"><strong>Spotting phishing.</strong> Be cautious with unexpected links/attachments, sender mismatches, urgency and requests for credentials. If unsure, do not click — report it.</li><li style=\"margin:0 0 6px\"><strong>Handling information.</strong> Follow the Information Classification guideline; share Confidential/Restricted information only on a need-to-know basis and through approved tools.</li><li style=\"margin:0 0 6px\"><strong>Devices & remote work.</strong> Keep devices patched, use only approved software and AI tools, and secure your home/mobile working environment.</li><li style=\"margin:0 0 6px\"><strong>Reporting.</strong> Report suspected incidents or lost devices immediately via the security channel — early reporting limits harm and is never penalised.</li><li style=\"margin:0 0 6px\"><strong>Programme delivery.</strong> Awareness is delivered at onboarding, refreshed at least annually, and reinforced through periodic simulated-phishing and short campaigns; completion is tracked.</li></ol><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">6. Records &amp; evidence</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Training completion records (onboarding and annual refresher).</li><li style=\"margin:0 0 5px\">Simulated-phishing campaign results and trends.</li><li style=\"margin:0 0 5px\">Campaign/communication log.</li><li style=\"margin:0 0 5px\">Acknowledgement of the Acceptable Use expectations.</li></ul><h3 style=\"font-size:13.5px;font-weight:700;color:#101828;margin:20px 0 7px;letter-spacing:-.1px\">7. References</h3><ul style=\"margin:0 0 9px;padding-left:20px\"><li style=\"margin:0 0 5px\">Information Security Policy §22.</li><li style=\"margin:0 0 5px\">ISO/IEC 27001 A.6.3 (awareness, education & training).</li><li style=\"margin:0 0 5px\">NIS2 Directive, Article 21 (cyber-hygiene & training).</li></ul>"
};
